import{_ as e,o as s,c as a,a2 as r}from"./chunks/framework.D7toiNRm.js";const u=JSON.parse('{"title":"Metrics","description":"","frontmatter":{},"headers":[],"relativePath":"reference/metrics.md","filePath":"reference/metrics.md","lastUpdated":1781454385000}'),i={name:"reference/metrics.md"};function d(o,t,n,c,l,p){return s(),a("div",null,[...t[0]||(t[0]=[r('<h1 id="metrics" tabindex="-1">Metrics <a class="header-anchor" href="#metrics" aria-label="Permalink to &quot;Metrics&quot;">​</a></h1><p>AOSC does not currently export Prometheus metrics or OpenSearch metrics. The supported monitoring surface today is the REST status data; external tooling can poll <code>_list</code> and <code>_status</code> if it needs time-series dashboards.</p><p>Use these surfaces for monitoring today:</p><div class="aosc-table-scroll"><table class="aosc-table"><thead><tr><th>Surface</th><th>What it provides</th></tr></thead><tbody><tr><td><code>GET /_plugins/_aosc/{index}/_status</code></td><td>Coordinator phase, shard phases, per-phase counters, errors.</td></tr><tr><td><code>GET /_plugins/_aosc/_list</code></td><td>Summary of active and terminal migrations.</td></tr><tr><td>OpenSearch logs</td><td>Structured AOSC log lines with migration, shard, phase, and event context.</td></tr><tr><td>OpenSearch node stats</td><td>Cluster health, indexing pressure, thread pools, JVM, disk, and shard state.</td></tr></tbody></table></div><p>Example status poll:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -s</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;http://localhost:9200/_plugins/_aosc/my-index-v1/_status&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> jq</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;{phase, shards}&#39;</span></span></code></pre></div><p>A future metrics integration may add first-class metric export, but no public metric names or PromQL queries are part of the current plugin contract.</p>',7)])])}const m=e(i,[["render",d]]);export{u as __pageData,m as default};
